export default function ElasticButton({ children, variant, width, height, range, buttonColor, borderColor, borderWidth, clickColor, disabled, type, "aria-label": ariaLabel, onClick, className, style, maxStretch, pluckForce, }: ElasticButtonProps): React.JSX.Element;

